'use client';

import { useState } from 'react';
import { Check, Copy } from 'lucide-react';

interface AnalysisCardsProps {
  analysis: {
    issue: string;
    root_cause: string;
    minimal_fix: string;
    improved_version: string;
    code_diff?: {
      original: string;
      fixed: string;
    };
  };
}

export default function AnalysisCards({ analysis }: AnalysisCardsProps) {
  const [isCopied, setIsCopied] = useState(false);

  const handleCopy = async (text: string) => {
    try {
      await navigator.clipboard.writeText(text);
      setIsCopied(true);
      setTimeout(() => setIsCopied(false), 2000);
    } catch (err) {
      console.error('Failed to copy text: ', err);
    }
  };

  return (
    <div className="space-y-4 animate-in fade-in duration-500">
      {/* ... previous cards remain unchanged below ... */}

      {/* Issue Detected */}
      <div className="group border border-border rounded-lg bg-card/50 backdrop-blur-sm p-6 hover:bg-card/60 transition-all duration-300 shadow-lg shadow-black/10 hover:shadow-black/20">
        <div className="flex items-start gap-3 mb-3">
          <div className="mt-1 w-2 h-2 rounded-full bg-red-500 flex-shrink-0" />
          <h3 className="text-sm font-semibold text-foreground">Issue Detected</h3>
        </div>
        <p className="text-sm text-muted-foreground leading-relaxed">
          {analysis.issue}
        </p>
      </div>

      {/* Root Cause Analysis */}
      <div className="group border border-border rounded-lg bg-card/50 backdrop-blur-sm p-6 hover:bg-card/60 transition-all duration-300 shadow-lg shadow-black/10 hover:shadow-black/20">
        <div className="flex items-start gap-3 mb-3">
          <div className="mt-1 w-2 h-2 rounded-full bg-amber-500 flex-shrink-0" />
          <h3 className="text-sm font-semibold text-foreground">Root Cause Analysis</h3>
        </div>
        <p className="text-sm text-muted-foreground leading-relaxed">
          {analysis.root_cause}
        </p>
      </div>

      {/* Minimal Fix */}
      <div className="group border border-border rounded-lg bg-card/50 backdrop-blur-sm p-6 hover:bg-card/60 transition-all duration-300 shadow-lg shadow-black/10 hover:shadow-black/20">
        <div className="flex items-start gap-3 mb-4">
          <div className="mt-1 w-2 h-2 rounded-full bg-green-500 flex-shrink-0" />
          <h3 className="text-sm font-semibold text-foreground">Minimal Fix</h3>
        </div>
        <pre className="bg-secondary/50 rounded border border-border p-4 overflow-x-auto">
          <code className="text-xs text-foreground font-mono whitespace-pre-wrap break-words">
            {analysis.minimal_fix}
          </code>
        </pre>
      </div>

      {/* Improved Version */}
      <div className="group border border-border rounded-lg bg-card/50 backdrop-blur-sm p-6 hover:bg-card/60 transition-all duration-300 shadow-lg shadow-black/10 hover:shadow-black/20">
        <div className="flex items-start justify-between mb-4">
          <div className="flex items-start gap-3">
            <div className="mt-1 w-2 h-2 rounded-full bg-blue-500 flex-shrink-0" />
            <h3 className="text-sm font-semibold text-foreground">Improved Version</h3>
          </div>
          <button
            onClick={() => handleCopy(analysis.improved_version)}
            className="flex items-center gap-1.5 px-2.5 py-1.5 rounded-md text-xs font-medium text-muted-foreground bg-secondary/50 hover:bg-secondary border border-border transition-colors group/copy"
            title="Copy to clipboard"
          >
            {isCopied ? (
              <>
                <Check className="w-3.5 h-3.5 text-green-500" />
                <span className="text-green-500">Copied</span>
              </>
            ) : (
              <>
                <Copy className="w-3.5 h-3.5 group-hover/copy:text-foreground transition-colors" />
                <span className="group-hover/copy:text-foreground transition-colors">Copy</span>
              </>
            )}
          </button>
        </div>
        <pre className="bg-secondary/50 rounded border border-border p-4 overflow-x-auto">
          <code className="text-xs text-foreground font-mono whitespace-pre-wrap break-words">
            {analysis.improved_version}
          </code>
        </pre>
      </div>

      {/* Code Diff */}
      {analysis.code_diff && (
        <div className="group border border-border rounded-lg bg-card/50 backdrop-blur-sm p-6 hover:bg-card/60 transition-all duration-300 shadow-lg shadow-black/10 hover:shadow-black/20">
          <div className="flex items-start gap-3 mb-4">
            <div className="mt-1 w-2 h-2 rounded-full bg-purple-500 flex-shrink-0" />
            <h3 className="text-sm font-semibold text-foreground">Code Diff</h3>
          </div>

          {/* Split View Container */}
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            {/* Original Code */}
            <div className="flex flex-col">
              <div className="text-xs font-semibold text-muted-foreground mb-2 px-3 py-1 bg-red-500/10 rounded">
                Original Code
              </div>
              <pre className="flex-1 bg-secondary/50 rounded border border-border border-red-500/20 p-4 overflow-x-auto">
                <code className="text-xs text-foreground font-mono whitespace-pre-wrap break-words">
                  {analysis.code_diff.original}
                </code>
              </pre>
            </div>

            {/* Fixed Code */}
            <div className="flex flex-col">
              <div className="text-xs font-semibold text-muted-foreground mb-2 px-3 py-1 bg-green-500/10 rounded">
                Fixed Code
              </div>
              <pre className="flex-1 bg-secondary/50 rounded border border-border border-green-500/20 p-4 overflow-x-auto">
                <code className="text-xs text-foreground font-mono whitespace-pre-wrap break-words">
                  {analysis.code_diff.fixed}
                </code>
              </pre>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}
